with open(locals()['var_function-call-6799515908634330403'], 'r') as f:
    civic_docs = json.load(f)

lines = []
for d in civic_docs:
    lines.extend(d.get('text', '').splitlines())

projects = []
current_project = None
current_section = "Unknown"

for i in range(len(lines)):
    line = lines[i].strip()
    if not line: continue

    if "Capital Improvement Projects" in line:
        current_section = "Capital"
    elif "Disaster Recovery Projects" in line:
        current_section = "Disaster"

    is_project = False
    if i + 1 < len(lines):
        next_line = lines[i+1].strip()
        # Relaxed check
        if "Updates:" in next_line or "Project Description:" in next_line:
             if "Agenda" not in line and "Page" not in line and len(line) < 200:
                 is_project = True

    if is_project:
        if current_project:
            projects.append(current_project)
        current_project = {
            "name": line,
            "section": current_section,
            "st": None,
            "is_disaster": False,
            "keywords": []
        }
        if current_section == "Disaster":
            current_project["is_disaster"] = True
        if "FEMA" in line or "CalOES" in line:
            current_project["is_disaster"] = True
            current_project["keywords"].append("Name")
    elif current_project:
        # Extract Date
        if "Begin Construction" in line:
            current_project["st"] = line

        # Check Keywords
        if "FEMA" in line:
            current_project["is_disaster"] = True
            current_project["keywords"].append("Body FEMA")
        if "CalOES" in line:
            current_project["is_disaster"] = True
            current_project["keywords"].append("Body CalOES")

if current_project:
    projects.append(current_project)

# Filter
targets = []
for p in projects:
    st = p.get("st")
    if st and "2022" in st:
        if p["is_disaster"]:
            targets.append(p)

print("__RESULT__:")
print(json.dumps([{"name": p["name"], "st": p["st"], "keywords": p["keywords"]} for p in targets]))
